// PATCH(namecheap-deterministic-cache-key): regression coverage for sorted cache-key parameters.
func TestCacheKeySortsParameters(t *testing.T) {
	c := &Client{}

	left := map[string]string{
		"Command":    "namecheap.domains.check",
		"DomainList": "example.com",
		"ApiUser":    "user",
	}
	right := map[string]string{
		"ApiUser":    "user",
		"DomainList": "example.com",
		"Command":    "namecheap.domains.check",
	}

	leftKey := c.cacheKey("/xml.response", left)
	rightKey := c.cacheKey("/xml.response", right)
	if leftKey != rightKey {
		t.Fatalf("cacheKey should be independent of map iteration/insertion order: %q != %q", leftKey, rightKey)
	}
}

